const body = $('PostCall Webhook').first().json.body;

const callStatus = body.call?.status || body.status || 'unknown';
const callId = body.call?.call_id || '';
const duration = body.call?.duration || 0;
const endReason = body.call?.end_call_reason || '';
const rawTranscript = body.call?.transcript || '';
const transcript = rawTranscript.replace(/\r\n/g, '\n').replace(/\r/g, '\n').replace(/"/g, "'").replace(/\n/g, '\\n').substring(0, 32000);
const recordingUrl = body.call?.recording_url || '';
const phone = body.lead?.phone_number || '';

const customVars = Array.isArray(body.custom_variables) ? body.custom_variables : [];
const callVars = Array.isArray(body.call?.custom_variables) ? body.call.custom_variables : [];
let leadId = '';
let campaign = '';
for (const v of [...customVars, ...callVars]) {
  if (v.key === 'leadId' && !leadId) leadId = v.value || '';
  if (v.key === 'campaign' && !campaign) campaign = v.value || '';
}

let sfStatus = 'Failed';
switch(callStatus) {
  case 'hangup_on_voicemail': sfStatus = 'Voicemail';  break;
  case 'completed':           sfStatus = 'Completed';  break;
  case 'no-answer':           sfStatus = 'No_Answer';  break;
  case 'no_answer':           sfStatus = 'No_Answer';  break;
  case 'busy':                sfStatus = 'Busy';       break;
  case 'failed':              sfStatus = 'Failed';     break;
  default:                    sfStatus = 'Failed';     break;
}

const startTime = body.call?.start_time || '';
const callDate = startTime ? startTime.split('T')[0] : new Date().toISOString().split('T')[0];

const phoneDigits = phone.replace(/\D/g, '');
const phoneSearch = phoneDigits.slice(-10);

console.log('PostCall — raw:', callStatus, '-> sf:', sfStatus, '| leadId:', leadId, '| phone:', phone);

return [{
  json: {
    callId, callStatus, sfStatus, transcript, recordingUrl,
    leadId, campaign, phone, phoneSearch, callDate, duration, endReason
  }
}];

